pure fn percentile_of(value: Number, sorted_list: [Number]) -> Number {
    n = length(sorted_list)
    rank = 0
    for i in range(0, n) {
        if sorted_list[i] <= value { rank = rank + 1 }
    }
    return (rank - 1) / (n - 1)
}
