def metaphor_for_overlap(elements):
    if not elements:
        return "empty intersection, no shared traits"
    if len(elements) == 1:
        return f"one shared trait: {elements[0]}"
    return f"{len(elements)} shared traits: {', '.join(map(str, elements))}"

