fn parse_and_validate_emails(text: Text) -> [Text] {
    emails = split(lower(text), " ")
    valid = []
    for e in emails {
        parsed = parse_email_address(e)
        if parsed != "" and validate_email_address(parsed) == "valid" {
            valid = append(valid, parsed)
        }
    }
    return valid
}

fn draft_greetings_for_emails(emails: [Text]) -> [Text] {
    greetings = []
    for e in emails {
        name = replace(e, "@", "")
        greeting = draft_greeting(name)
        greetings = append(greetings, join(["To ", e, ": ", greeting], ""))
    }
    return greetings
}

entry main(text: Text) {
    emails = parse_and_validate_emails(text)
    return join(draft_greetings_for_emails(emails), "\n")
}

